// Install the React component
npm install @zkira/react-widget

// Use in your React app
import { ZkiraPayButton } from '@zkira/react-widget'

function PaymentPage() {
  const handleSuccess = (txId: string) => {
    console.log('Payment successful:', txId)
  }

  return (
    <ZkiraPayButton
      amount={100}
      token="USDC"
      theme="dark"
      onSuccess={handleSuccess}
      onError={(err) => console.error(err)}
    />
  )
}

// Create payment widget iframe
const widget = createZkiraPayment({
  amount: 100,
  token: 'USDC',
  container: '#payment-widget',
  theme: 'light',
  onSuccess: (data) => {
    console.log('Payment complete', data.txId)
  }
})

// Listen for widget events
window.addEventListener('message', (event) => {
  if (event.data.type === 'PAYMENT_SUCCESS') {
    // Handle success
  }
})
